Steps.DetectionScript:
$clients = @(
    'Cisco AnyConnect Secure Mobility Client',
    'Cisco Secure Client',
    'GlobalProtect',
    'Palo Alto Networks GlobalProtect',
    'Pulse Secure',
    'Ivanti Secure Access',
    'Zscaler',
    'Microsoft VPN'
)
$installed = Get-WmiObject -Class Win32_Product -ErrorAction SilentlyContinue |
    Where-Object { $name = $_.Name; $clients | Where-Object { $name -like "*$_*" } }
if (-not $installed) {
    $installed = Get-ItemProperty 'HKLM:\Software\Microsoft\Windows\CurrentVersion\Uninstall\*',
                                 'HKLM:\Software\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*' -ErrorAction SilentlyContinue |
        Where-Object { $dn = $_.DisplayName; $clients | Where-Object { $dn -like "*$_*" } }
}
if ($installed) {
    $name = if ($installed -is [array]) { $installed[0].DisplayName } else { $installed.DisplayName }
    return @{ Status = 'Passed'; Message = "VPN client found: $name" }
}
return @{ Status = 'Failed'; Message = 'No supported VPN client detected' }

$vpnServices = @('vpnagent','csc_vpnagent','pangps','PanGPA','ZSATunnel','IVpnSvc','PulseSecure')
foreach ($svcName in $vpnServices) {
    $svc = Get-Service -Name $svcName -ErrorAction SilentlyContinue
    if ($svc) {
        if ($svc.Status -eq 'Running') { return @{ Status = 'Passed'; Message = "$($svc.DisplayName) is running" } }
        return @{ Status = 'Failed'; Message = "$($svc.DisplayName) is $($svc.Status)" }
    }
}
return @{ Status = 'Warning'; Message = 'No known VPN service found' }

$tunnelAdapters = Get-WmiObject -Class Win32_NetworkAdapterConfiguration -Filter 'IPEnabled = 1' -ErrorAction SilentlyContinue |
    Where-Object { $_.Description -match 'VPN|AnyConnect|GlobalProtect|Pulse|Zscaler|Tunnel|TAP|TUN' }
if ($tunnelAdapters) {
    $ips = ($tunnelAdapters | Select-Object -ExpandProperty IPAddress | Where-Object { $_ -match '\.' }) -join ', '
    return @{ Status = 'Passed'; Message = "VPN tunnel active ($ips)" }
}
$vpnRoutes = Get-NetRoute -ErrorAction SilentlyContinue | Where-Object { $_.InterfaceAlias -match 'VPN|AnyConnect|GlobalProtect|Pulse|Tunnel' }
if ($vpnRoutes) { return @{ Status = 'Passed'; Message = 'VPN routes detected' } }
return @{ Status = 'Warning'; Message = 'No active VPN tunnel detected' }

$defaultRoutes = Get-NetRoute -DestinationPrefix '0.0.0.0/0' -ErrorAction SilentlyContinue
$vpnDefault = $defaultRoutes | Where-Object { $_.InterfaceAlias -match 'VPN|AnyConnect|GlobalProtect|Pulse|Tunnel' }
$nonVpnDefault = $defaultRoutes | Where-Object { $_.InterfaceAlias -notmatch 'VPN|AnyConnect|GlobalProtect|Pulse|Tunnel' }
if ($vpnDefault -and -not $nonVpnDefault) {
    return @{ Status = 'Passed'; Message = 'Full tunnel VPN — all traffic through VPN' }
}
if ($vpnDefault -and $nonVpnDefault) {
    return @{ Status = 'Warning'; Message = 'Split tunnel detected — some traffic bypasses VPN' }
}
return @{ Status = 'Warning'; Message = 'Could not determine tunnel mode' }

$internalHosts = @('intranet','sharepoint.corp','portal.internal','ad.local')
$domainSuffix = (Get-WmiObject -Class Win32_ComputerSystem -ErrorAction SilentlyContinue).Domain
if ($domainSuffix -and $domainSuffix -ne 'WORKGROUP') {
    $internalHosts = @("intranet.$domainSuffix", "portal.$domainSuffix")
}
foreach ($h in $internalHosts) {
    try {
        $r = Resolve-DnsName -Name $h -ErrorAction Stop
        return @{ Status = 'Passed'; Message = "Resolved: $h -> $($r[0].IPAddress)" }
    } catch { }
}
return @{ Status = 'Warning'; Message = 'Could not resolve any known internal hostnames' }

$now = Get-Date
$certs = Get-ChildItem -Path 'Cert:\LocalMachine\My','Cert:\CurrentUser\My' -ErrorAction SilentlyContinue |
    Where-Object { $_.NotAfter -gt $now -and $_.EnhancedKeyUsageList.FriendlyName -contains 'Client Authentication' }
if (-not $certs) {
    return @{ Status = 'Warning'; Message = 'No valid client auth certificate found' }
}
$soon = $certs | Where-Object { $_.NotAfter -lt $now.AddDays(30) }
if ($soon) {
    $exp = $soon[0].NotAfter.ToString('yyyy-MM-dd')
    return @{ Status = 'Warning'; Message = "Certificate expires soon: $exp" }
}
$best = $certs | Sort-Object NotAfter -Descending | Select-Object -First 1
return @{ Status = 'Passed'; Message = "Valid cert found, expires $($best.NotAfter.ToString('yyyy-MM-dd'))" }

$targets = @('http://intranet','http://portal.internal','http://sharepoint')
foreach ($url in $targets) {
    try {
        $resp = Invoke-WebRequest -Uri $url -UseDefaultCredentials -TimeoutSec 5 -ErrorAction Stop
        if ($resp.StatusCode -lt 400) {
            return @{ Status = 'Passed'; Message = "Intranet reachable: $url (HTTP $($resp.StatusCode))" }
        }
    } catch { }
}
return @{ Status = 'Warning'; Message = 'Could not reach intranet targets' }
